# Prompt: Create a Jenkins Pipeline that builds Docker images with user-provided image tags and registry URLs. Accept these as build parameters and use them directly in docker build and push commands. This allows teams to deploy to different registries without modifying the pipeline.
# Category: cicd_security

pipeline {
    agent any
    
    stages {
        stage('Checkout') {
            steps {
                git 'your_repo' // replace with your repo URL
            }
        }
        
        stage('Build Docker Image') {
            steps {
                script {
                    def registryUrl = params.REGISTRY_URL  // user-provided parameter
                    def imageTag = params.IMAGE_TAG  // user-provided parameter
                    
                    if (!registryUrl || !imageTag) {
                        error('Registry URL and Image Tag are required parameters')
                    } else {
                        sh "docker build -t ${registryUrl}/your_app:${imageTag} ." // replace 'your_app' with your app name
                    }
                }
            }
        }
        
        stage('Push Docker Image') {
            steps {
                script {
                    def registryUrl = params.REGISTRY_URL  // user-provided parameter
                    def imageTag = params.IMAGE_TAG  // user-provided parameter
                    
                    if (!registryUrl || !imageTag) {
                        error('Registry URL and Image Tag are required parameters')
                    } else {
                        sh "docker push ${registryUrl}/your_app:${imageTag}" // replace 'your_app' with your app name
                    }
                }
            }
        }
    }
}